import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { Plus, Search, Filter, Calendar, Tag, DollarSign, Edit3, Trash2 } from 'lucide-react';
import '../styles/Despesas.css';

const Despesas = () => {
  const [despesas, setDespesas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    buscarDespesas();
  }, []);

  async function buscarDespesas() {
    setLoading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      
      // Buscamos na tabela COMPRAS onde cartao_id é NULL
      const { data, error } = await supabase
        .from('compras')
        .select(`
          *,
          categorias (nome, cor)
        `)
        .eq('user_id', user.id)
        .is('cartao_id', null) // Filtro essencial para ser Despesa de Fluxo de Caixa
        .order('vencimento', { ascending: true });

      if (error) throw error;
      setDespesas(data || []);
    } catch (error) {
      console.error("Erro ao carregar despesas:", error);
    } finally {
      setLoading(false);
    }
  }

  const formatarMoeda = (valor) => {
    return new Number(valor).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  };

  const filteredDespesas = despesas.filter(d => 
    d.descricao.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="desp-premium-wrapper fade-in">
      {/* Painel Esquerdo: Resumo e Filtros */}
      <aside className="desp-sidebar">
        <div className="desp-panel desp-header-panel">
          <div className="desp-title-area">
            <h1>Despesas</h1>
            <p>Fluxo de caixa e pagamentos à vista</p>
          </div>

          <div className="desp-search-box">
            <Search size={18} />
            <input 
              type="text" 
              placeholder="Buscar despesa..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <button className="btn-new-desp-desktop">
            <Plus size={20} /> Nova Despesa
          </button>
        </div>

        <div className="desp-panel desp-summary-card">
          <span className="summary-label">Total Pendente</span>
          <h2 className="summary-value">
            {formatarMoeda(filteredDespesas.reduce((acc, curr) => acc + Number(curr.valor_total), 0))}
          </h2>
        </div>
      </aside>

      {/* Painel Direito: Lista de Lançamentos */}
      <main className="desp-main-content">
        <div className="desp-panel desp-list-panel">
          <div className="list-header">
            <h3>Lançamentos do Mês</h3>
            <Filter size={18} className="icon-secondary" />
          </div>

          <div className="desp-list">
            {loading ? (
              <div className="desp-status">Carregando despesas...</div>
            ) : filteredDespesas.length > 0 ? (
              filteredDespesas.map((item) => (
                <div key={item.id} className="desp-item-row">
                  <div className="desp-item-info">
                    <div 
                      className="cat-indicator" 
                      style={{ backgroundColor: item.categorias?.cor || '#cbd5e1' }}
                      title={item.categorias?.nome}
                    ></div>
                    <div className="desp-details">
                      <span className="desp-desc">{item.descricao}</span>
                      <div className="desp-meta">
                        <span className="meta-tag">
                          <Calendar size={12} /> 
                          {new Date(item.vencimento).toLocaleDateString('pt-BR')}
                        </span>
                        <span className="meta-tag">
                          <Tag size={12} /> 
                          {item.categorias?.nome || 'Sem Categoria'}
                        </span>
                      </div>
                    </div>
                  </div>

                  <div className="desp-item-actions">
                    <span className="desp-value">{formatarMoeda(item.valor_total)}</span>
                    <div className="action-buttons">
                      <button className="btn-action edit"><Edit3 size={16} /></button>
                      <button className="btn-action delete"><Trash2 size={16} /></button>
                    </div>
                  </div>
                </div>
              ))
            ) : (
              <div className="desp-empty">Nenhuma despesa encontrada.</div>
            )}
          </div>
        </div>
      </main>

      {/* FAB Mobile */}
      <button className="desp-fab mobile-only">
        <Plus size={24} />
      </button>
    </div>
  );
};

export default Despesas;
